func doWorkerServerRequest(req *http.Request) (*http.Response, error) {
	client := newLocalServerClient()
	resp, err := client.Do(req)
	if err == nil || !shouldRetryWorkerServerReadiness(req, err) {
		return resp, err
	}
	if workerServerReadinessRetryBudget <= 0 {
		return nil, err
	}

	deadline := time.Now().Add(workerServerReadinessRetryBudget)
	lastErr := err
	for time.Now().Before(deadline) {
		time.Sleep(workerServerReadinessRetryDelay)
		retryReq, cloneErr := cloneRequestForRetry(req)
		if cloneErr != nil {
			return nil, cloneErr
		}
		resp, err = client.Do(retryReq)
		if err == nil {
			return resp, nil
		}
		if !shouldRetryWorkerServerReadiness(retryReq, err) {
			return nil, err
		}
		lastErr = err
	}
	return nil, fmt.Errorf("local server readiness timeout after %s: %w", workerServerReadinessRetryBudget, lastErr)
}

func cloneRequestForRetry(req *http.Request) (*http.Request, error) {
	retryReq := req.Clone(req.Context())
	if req.Body != nil {
		if req.GetBody == nil {
			return nil, fmt.Errorf("cannot retry %s %s: request body is not replayable", req.Method, req.URL.Redacted())
		}
		body, err := req.GetBody()
		if err != nil {
			return nil, fmt.Errorf("replay request body: %w", err)
		}
		retryReq.Body = body
	}
	return retryReq, nil
}

func shouldRetryWorkerServerReadiness(req *http.Request, err error) bool {
	return req != nil && req.URL != nil && isLocalWorkerServerURL(req.URL) && isConnectionRefused(err)
}

func isLocalWorkerServerURL(u *urlpkg.URL) bool {
	host := u.Hostname()
	if host == "" {
		host = u.Host
		if splitHost, _, err := net.SplitHostPort(host); err == nil {
			host = splitHost
		}
	}
	host = strings.Trim(host, "[]")
	switch strings.ToLower(host) {
	case "localhost", "127.0.0.1", "::1":
		return true
	default:
		return false
	}
}

func isConnectionRefused(err error) bool {
	if err == nil {
		return false
	}
	if errors.Is(err, syscall.ECONNREFUSED) {
		return true
	}
	if strings.Contains(strings.ToLower(err.Error()), "connection refused") {

		cancel()
	}
	s.beadHub.Close()
	s.workers.StopAll()
	s.workers.LandCoordinators.StopAll()
	return nil
}

// ListenAndServe starts the server. If TsnetConfig.Enabled is true, a parallel
// Tailscale ts-net listener is started alongside the standard localhost listener.
func (s *Server) ListenAndServe() error {
	release, err := acquireSingletonLock()
	if err != nil {
		return err
	}
	defer release()
	s.installSingletonReleaseOnSignal(release)
	s.writeAddrFile("http")
	s.reconcileDesiredWorkersAfterStartup()
	if s.TsnetConfig != nil && s.TsnetConfig.Enabled {
		errCh := make(chan error, 2)

		// Standard localhost listener
		go func() {
			errCh <- http.ListenAndServe(s.Addr, s.mux)
		}()

		// ts-net listener
		go func() {
			errCh <- s.listenTsnet()
		}()

		return <-errCh
	}
	return http.ListenAndServe(s.Addr, s.mux)
}

// ListenAndServeTLS starts the server with TLS. If certFile and keyFile are
// empty, a self-signed certificate is auto-generated and cached under
// workingDir/.ddx/server/tls/.
func (s *Server) ListenAndServeTLS(certFile, keyFile string) error {
	release, err := acquireSingletonLock()
	if err != nil {
		return err
	}
	defer release()
	s.installSingletonReleaseOnSignal(release)
	if certFile == "" || keyFile == "" {
		var err error
		tlsDir := ddxroot.JoinProject(s.WorkingDir, "server", "tls")
		certFile, keyFile, err = ensureSelfSignedCert(tlsDir)
		if err != nil {
			return fmt.Errorf("generating self-signed cert: %w", err)
		}
	}
	s.writeAddrFile("https")
	s.reconcileDesiredWorkersAfterStartup()
	if s.TsnetConfig != nil && s.TsnetConfig.Enabled {
		errCh := make(chan error, 2)
		go func() {
			errCh <- http.ListenAndServeTLS(s.Addr, certFile, keyFile, s.mux)
		}()
		go func() {
			errCh <- s.listenTsnet()
		}()
		return <-errCh
	}
	return http.ListenAndServeTLS(s.Addr, certFile, keyFile, s.mux)
}

func (s *Server) reconcileDesiredWorkersAfterStartup() {
