	// shelling out to a real agent harness.
	tryExecutorOverride agent.ExecuteBeadExecutor

	// proseEvidenceHookOverride, when non-nil, replaces the default
	// post-attempt prose evidence hook used by ddx try and ddx work. Tests
	// inject this to assert hook invocation timing and behavior without
	// running real git/docprose commands.
	proseEvidenceHookOverride agent.ProseEvidenceHook

	// durableAuditFinalizeOverride, when non-nil, replaces the default
	// DDx-managed audit finalizer used by ddx try and ddx work after an
	// attempt's durable tracker mutations are complete.
	durableAuditFinalizeOverride func(report agent.ExecuteBeadReport) error

	// resourceCheckerOverride, when non-nil, replaces the default execution
	// resource preflight used by ddx try and ddx work.
	resourceCheckerOverride agent.ExecutionResourceChecker

	// registryOverride, when non-nil, replaces the built-in plugin registry
	// for install/list/show command tests.
	registryOverride *registry.Registry

	// workBinaryPathOverride, when non-nil, resolves the installed ddx binary
	// used for watch-mode self-refresh checks.
	workBinaryPathOverride func() string

	// workBinaryReexecOverride, when non-nil, replaces the in-place exec used
	// by watch-mode self-refresh. Tests inject this to capture argv/env without
	// replacing the process image.
	workBinaryReexecOverride func(exe string, argv []string, env []string, dir string) error

	// workerScannerOverride, when non-nil, replaces the live-process worker
	// scanner used by "ddx work status". Tests inject a fixed snapshot so
	// the command can be exercised without spawning real worker processes.
	workerScannerOverride workerStatusScanner

	// preflightWarnOnce ensures the project-local skill layout warning fires at
	// most once per process for long-running entrypoints (work, try).
	preflightWarnOnce sync.Once

	// serverListenAndServeOverride, when non-nil, replaces srv.ListenAndServeTLS
	// in the server RunE. Used by tests to verify server startup behavior without
	// actually binding to a port.
	serverListenAndServeOverride func(string, string) error

	// Custom viper instance for isolation
	viperInstance *viper.Viper

	// Update checker instance (stores check result for PostRunE)
	updateChecker *update.Checker
	updateDone    chan struct{}
	updateMu      sync.Mutex
}

// NewCommandFactory creates a new command factory with default settings
func NewCommandFactory(workingDir string) *CommandFactory {
	return &CommandFactory{
		Version:       Version,
		Commit:        Commit,
		Date:          Date,
		WorkingDir:    workingDir,
		viperInstance: viper.New(),
	}
}

// NewRootCommand creates a fresh root command with all subcommands
